def precision_at_k(predicted: Sequence[str], relevant: Sequence[str], k: int = 3) -> float:
    if k <= 0:
        return 0.0
    pred_k = list(predicted)[:k]
    if not pred_k:
        return 0.0
    rel = set(relevant)
    hits = sum(1 for item in pred_k if item in rel)
    return hits / len(pred_k)

